\begin{table}[htbp]
\centering
\caption{DAB变换器系统设计规格}
\label{tab:specifications}
\begin{tabular}{lc}
\toprule
\textbf{参数名称} & \textbf{规格值} \\
\midrule
\multicolumn{2}{c}{\textbf{电气参数}} \\
\cmidrule(lr){1-2}
输入直流电压 $V_1$ & 95\,V \\
输出直流电压 $V_2$ & 380\,V \\
电压变比 $V_2/V_1$ & 4:1 \\
\midrule
\multicolumn{2}{c}{\textbf{性能指标}} \\
\cmidrule(lr){1-2}
额定输出功率 $P_n$ & 2\,kW \\
开关频率 $f_{sw}$ & 250\,kHz \\
效率目标 $\eta_{target}$ & $\geq 98\%$（满载） \\
\midrule
\multicolumn{2}{c}{\textbf{运行特性}} \\
\cmidrule(lr){1-2}
功率传输方向 & 双向（正向为主要设计工况） \\
\bottomrule
\end{tabular}
\end{table}
